import{C as s,o as n,c as l,a5 as a,E as r}from"./chunks/framework.CW28V7p_.js";const p=JSON.parse('{"title":"⭐ Module 0 — Final quiz","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/final-quiz.md","filePath":"module-0/final-quiz.md","lastUpdated":1780937944000}'),i={name:"module-0/final-quiz.md"},m=Object.assign(i,{setup(d){const t={id:"m0-final",title:"⭐ Module 0 — Final quiz",intro:"15 питань що перевіряють синтез усіх 8 секцій. Якщо < 80% правильно — повернись у секції з найбільшими прорахунками.",questions:[{type:"mcq",q:"Чому release build agave займає 25-30 хвилин а не 5? (обери всі правильні)",options:["Agave має ~600 dependencies, кожна компілюється окремо","Release optimization (LTO, inlining) повільніша за debug compile","Кожен build re-downloads dependencies з мережі","Linker з'єднує величезну кількість object files у фінальний binary"],correct:[0,1,3],explanation:"Release build повільний бо: (1) ~600 крейтів × release optimization, (2) LTO робить cross-crate optimization у linker stage. Network — тільки на першому build (потім cached). Module 0.1 + 0.3."},{type:"compare",q:"У чому ключова різниця між cargo build і cargo install?",ideal:"cargo build компілить у target/ директорію поточного repo — binary залишається там. cargo install компілить АБО з crates.io АБО з --path, і копіює готовий binary у persistent location (~/.cargo/bin/ за дефолтом або --root). Build для development/testing, install для глобального використання як CLI tool. cargo install default = release, cargo build default = debug.",explanation:"Ключове: build залишає у target/, install копіює у persistent dir. Default modes теж різні. Module 0.3."},{type:"command",q:"Як відкинути локальні зміни в одному файлі (наприклад src/main.rs)?",accepts:["git checkout -- src/main.rs","git restore src/main.rs","git checkout src/main.rs"],ideal:"git checkout -- src/main.rs",explanation:"git checkout -- <file> класичний синтаксис, modern equivalent: git restore. Module 0.2."},{type:"diagnose",q:"systemctl status solana показує Active: failed (Result: signal). Process exited (status=9/KILL). Найвірогідніша причина?",options:["OOM killer вбив validator process — недостатньо RAM","У ExecStart typo, validator одразу exited","Hardware failure","Validator потребує root permissions"],correct:[0],explanation:"status=9/KILL = SIGKILL = OOM killer (kernel вбиває коли немає RAM). status=1/FAILURE або status=2 — щось інше (exit code від programu). Module 0.4."},{type:"mcq",q:"Що з цього є daemon? (обери всі)",options:["agave-validator який запущений через systemctl","cat /etc/passwd запущений у твоєму terminal","tmux server","sshd (SSH server) на сервері"],correct:[0,2,3],explanation:"Daemon = background process відв'язаний від terminal, керується init системою. agave-validator через systemd, tmux server (теж detached), sshd. cat у terminal — foreground process. Module 0.4."},{type:"scenario",q:"Ти на сервері WNX0016778 як devops_ssh. Хочеш видалити content /home/solana/solana/ledger/. Які 2 правильні підходи (з urахуванням permission footgun)?",ideal:`1. sudo bash -c "rm -rf /home/solana/solana/ledger/*" — bash запускається як root, експандить * правильно.

2. sudo find /home/solana/solana/ledger -mindepth 1 -delete — find працює як root, traverses папку, видаляє content.

Чому НЕ працює просто sudo rm -rf /home/solana/solana/ledger/* — shell expand * ПЕРЕД sudo, а devops_ssh не може читати папку (mode 750), тому * лишається literal, нічого не видаляється.`,explanation:"Module 0.5 — глобальна expansion timing проблема. Якщо ти описала обидва підходи + чому raw command не працює — повна відповідь."},{type:"compare",q:"У чому різниця між symlink і hardlink?",ideal:`Symlink — це окремий файл який містить ШЛЯХ до іншого файлу. Hardlink — це АЛЬТЕРНАТИВНЕ ІМ'Я для того ж inode (тих же даних на диску).

Key differences:
1. Symlink може перетинати filesystems, hardlink ні (один inode = один fs)
2. Symlink працює для папок, hardlink зазвичай ні
3. Якщо target symlink видалити — symlink стає broken (вказує в нікуди). Hardlink не ламається, бо data існує доки є хоч один hardlink на inode
4. ln -s = symlink, ln (без -s) = hardlink`,explanation:"Ключове: symlink = file with path; hardlink = alternative name for same inode. Module 0.5."},{type:"command",q:"Як подивитись на що вказує symlink /home/solana/ag?",accepts:["readlink /home/solana/ag","sudo readlink /home/solana/ag","ls -la /home/solana/ag","sudo ls -la /home/solana/ag","readlink -f /home/solana/ag"],ideal:"sudo readlink /home/solana/ag",explanation:"sudo бо /home/solana має mode 750. readlink показує target. ls -la теж показує через -> notation. Module 0.5."},{type:"diagnose",q:'Ти запускаєш sudo doublezero-solana ... і отримуєш "command not found". Без sudo команда працює. Що з цього є вірогідною причиною?',options:["sudo resets PATH за замовчуванням, doublezero-solana не у sudo PATH","sudo вимагає absolute path","doublezero-solana не дозволено для root","Binary потребує middleware"],correct:[0],explanation:'sudo по default resets PATH до secure_path. Tools у ~/.cargo/bin/ або не у secure_path локаціях — sudo не знаходить. Fix: sudo env "PATH=$PATH" command. Module 0.6.'},{type:"mcq",q:"Які квоти роблять variable expansion у bash? (обери всі правильні)",options:["Без лапок (raw)",'Double quotes "..."',"Single quotes '...'","Backticks `...`"],correct:[0,1],explanation:"Без лапок і double quotes роблять variable expansion ($VAR → значення). Single quotes — НЕ роблять (literal). Backticks — command substitution, окрема річ. Module 0.6."},{type:"scenario",q:'Ти запустила agave build у tmux session "build" (25 хв процес). Через 10 хв пропав інтернет. Опиши що відбувається з build, як reconnect.',ideal:`Build продовжує працювати у tmux session навіть після SSH disconnect. tmux server (background daemon) залишається живим коли твій SSH client вмирає. Process tree: tmux server → bash → build process — всі живі.

Reconnect:
1. Дочекатись інтернету і SSH-итись назад: ssh devops_ssh@WNX0016778
2. Подивитись чи сесія жива: tmux ls — має показати "build: 1 windows..."
3. Reattach: tmux attach -t build
4. Побачиш поточний стан build (можливо вже завершився)

Якщо БЕЗ tmux — SSH disconnect → SIGHUP вб'є bash + build process. 10 хвилин компіляції втрачені.`,explanation:"Ключове: tmux server detached від SSH connection, виживає disconnect. Якщо описала reconnect через ssh + tmux attach — повна відповідь. Module 0.7."},{type:"command",q:"Як detach з tmux session не вбиваючи її? (вкажи keyboard combo)",accepts:["Ctrl+B D","Ctrl+B d","Ctrl-B D","Ctrl-B d","C-b d","C-b D"],ideal:"Ctrl+B D",explanation:"Ctrl+B (default tmux prefix) потім D (detach). Module 0.7."},{type:"explain",q:"Поясни своїми словами як SSH key-based authentication працює. Чому це безпечніше за password.",ideal:`SSH key-based використовує asymmetric crypto. Пара ключів: private (на ноутбуці, ~/.ssh/id_ed25519) + public (копія на сервері у ~/.ssh/authorized_keys).

Flow:
1. SSH client connects до сервера
2. Сервер дивиться authorized_keys, знаходить твій public key
3. Сервер генерує random challenge, шифрує його твоїм public key
4. Передає encrypted challenge тобі
5. Твій private key decrypts його — тільки private key може
6. Sends decrypted answer назад
7. Server verifies — auth pass

Чому безпечніше за password:
- Private key ніколи не передається мережею
- Brute-force impossible (256+ bits vs 8-char password)
- Можна protect ще passphrase (двофакторний доступ)`,explanation:"Ключове: asymmetric pair, private never leaves laptop, challenge-response. Module 0.8."},{type:"command",q:"Як скопіювати файл backup.json з /tmp/ на сервері eta на твій ~/Desktop/ ноутбука?",accepts:["scp devops_ssh@eta:/tmp/backup.json ~/Desktop/","scp devops_ssh@eta:/tmp/backup.json /Users/monkeynest/Desktop/","scp devops_ssh@eta:/tmp/backup.json ~/Desktop"],ideal:"scp devops_ssh@eta:/tmp/backup.json ~/Desktop/",explanation:"scp <remote-source> <local-dest>. Якщо eta у ~/.ssh/config — short alias OK. ~ expandsо до твого home. Module 0.8."},{type:"order",q:"Постав у правильному порядку steps для agave upgrade build (Випадок B з 0.1 — build from source на mainnet):",items:["cargo build --release --bin agave-validator","sudo cp target/release/agave-validator ~/.local/share/solana/install/active_release/bin/","git fetch --tags","cd ~/agave","git checkout v2.1.0","sudo systemctl restart solana"],correctOrder:[3,2,4,0,1,5],explanation:"cd → fetch → checkout → build → copy → restart. Spočátku ентер репо, потім git операції, тоді cargo build, копія binary у agave-install layout, restart service. Module 0.1 Випадок B."},{type:"mcq",q:"WSL2 для Solana operator? (обери всі правильні)",options:["Повний Linux kernel у Hyper-V VM, full Solana compatibility","Replaces WSL1 (which had partial compat)","OK для dev, CLI, SSH; не для production validator","Сolana ledger варто розмістити у /mnt/c/ для backup"],correct:[0,1,2],explanation:"WSL2 — full Linux, для dev OK. Production validator на bare metal. Ledger у /mnt/c/ — slow Windows mount, never! Module 0.9."}]};return(c,e)=>{const o=s("Quiz");return n(),l("div",null,[e[0]||(e[0]=a('<h1 id="⭐-module-0-—-final-quiz" tabindex="-1">⭐ Module 0 — Final quiz <a class="header-anchor" href="#⭐-module-0-—-final-quiz" aria-label="Permalink to &quot;⭐ Module 0 — Final quiz&quot;">​</a></h1><blockquote><p>Цей quiz перевіряє чи ти зрозуміла всі 8 секцій Module 0. <strong>15 питань, ~30 хвилин.</strong> Усі типи: MCQ, command writing, scenario, diagnose, compare, explain, order.</p></blockquote><h2 id="як-проходити" tabindex="-1">Як проходити <a class="header-anchor" href="#як-проходити" aria-label="Permalink to &quot;Як проходити&quot;">​</a></h2><ul><li><strong>Чесно</strong>: не підглядай у секції під час quiz, інакше нема сенсу</li><li><strong>Self-grade чесно</strong>: для explain/scenario/compare питань відповідай і <strong>порівнюй з ідеальною</strong> перш ніж тиснути self-grade button</li><li><strong>Цільте на 80%+ correct</strong>: &lt; 80% → повернись у секції з прорахунками</li><li><strong>Progress зберігається</strong> у localStorage: можеш закрити браузер, повернутись завтра</li></ul><h2 id="quiz" tabindex="-1">Quiz <a class="header-anchor" href="#quiz" aria-label="Permalink to &quot;Quiz&quot;">​</a></h2>',5)),r(o,{data:t}),e[1]||(e[1]=a('<h2 id="результат" tabindex="-1">Результат <a class="header-anchor" href="#результат" aria-label="Permalink to &quot;Результат&quot;">​</a></h2><p>Після Submit:</p><table tabindex="0"><thead><tr><th>Результат</th><th>Що далі</th></tr></thead><tbody><tr><td><strong>13-15 / 15</strong> (87-100%)</td><td>Готова до Module 1 (Solana foundations)</td></tr><tr><td><strong>10-12 / 15</strong> (67-83%)</td><td>Повторити секції з помилками, потім re-take</td></tr><tr><td><strong>&lt; 10 / 15</strong></td><td>Прочитати модуль ще раз, потім re-take quiz через тиждень</td></tr></tbody></table><h2 id="що-далі-—-module-1" tabindex="-1">Що далі — Module 1 <a class="header-anchor" href="#що-далі-—-module-1" aria-label="Permalink to &quot;Що далі — Module 1&quot;">​</a></h2><p><a href="/module-1/">Module 1: Solana foundations</a> — починаємо з Solana-специфічних концептів: slot, epoch, leader, cluster, account model, transaction lifecycle. Будуємось на fundamentals з Module 0.</p><hr><p><strong>Попередньо:</strong> <a href="/module-0/8-ssh">← 8. SSH</a> | <strong>Наступне:</strong> <a href="/module-1/">Module 1: Solana foundations →</a> (🚧 не написано)</p>',7))])}}});export{p as __pageData,m as default};
